arguments.file_text:
@if (!Products.Any())
{
    <div class="alert alert-info text-center my-4">
        <h5 class="mb-1">No products found</h5>
        <p class="mb-0">Try adjusting your filters or clearing them to see more results.</p>
    </div>
}
else
{
    <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
        @foreach (var product in Products)
        {
            <div class="col">
                <ProductCard Product="product"
                             OnSelected="OnProductSelected"
                             OnAddToCart="OnAddToCart" />
            </div>
        }
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = [];

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@if (TotalPages > 1)
{
    <nav aria-label="Product pagination" class="mt-4">
        <ul class="pagination justify-content-center mb-0">
            <li class="page-item @(CurrentPage <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(CurrentPage - 1)" disabled="@(CurrentPage <= 1)">
                    Previous
                </button>
            </li>

            @foreach (var page in PageNumbers)
            {
                <li class="page-item @(page == CurrentPage ? "active" : "")">
                    <button class="page-link" @onclick="() => GoToPage(page)">@page</button>
                </li>
            }

            <li class="page-item @(CurrentPage >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="() => GoToPage(CurrentPage + 1)" disabled="@(CurrentPage >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter] public int CurrentPage { get; set; } = 1;
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int PageSize { get; set; } = 12;
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private int TotalPages => PageSize > 0 ? (int)Math.Ceiling((double)TotalCount / PageSize) : 1;

    private IEnumerable<int> PageNumbers
    {
        get
        {
            // Show up to 5 pages centered around current page
            var start = Math.Max(1, CurrentPage - 2);
            var end = Math.Min(TotalPages, start + 4);
            start = Math.Max(1, end - 4);

            for (int i = start; i <= end; i++)
                yield return i;
        }
    }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != CurrentPage)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}

@page "/catalog"
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-4">Product Catalog</h3>

@if (_error is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-3">
            <CatalogSidebar Categories="_categories" OnFilterApplied="HandleFilterApplied" />
        </div>

        <div class="col-md-9">
            @if (_loading)
            {
                <div class="d-flex justify-content-center align-items-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                    <span class="ms-2">Loading products…</span>
                </div>
            }
            else
            {
                <CatalogToolbar SortBy="@_sortBy"
                                TotalCount="_result.TotalCount"
                                Page="_result.Page"
                                PageSize="_result.PageSize"
                                OnSortChanged="HandleSortChanged" />

                <ProductGrid Products="_result.Items"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination CurrentPage="_currentPage"
                                   TotalCount="_result.TotalCount"
                                   PageSize="_pageSize"
                                   OnPageChanged="HandlePageChanged" />
            }
        </div>
    </div>
}

@code {
    /// <summary>
    /// Raised when a product card is clicked, allowing the parent to navigate to a detail page.
    /// </summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string> _categories = [];
    private PagedResult<Product> _result = new([], 0, 1, 12);
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int _pageSize = 12;
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        await LoadInitialDataAsync();
    }

    private async Task LoadInitialDataAsync()
    {
        try
        {
            _loading = true;
            _error = null;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, _pageSize);
            await Task.WhenAll(categoriesTask, productsTask);

            _categories = await categoriesTask;
            _result = await productsTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            _loading = true;
            _error = null;
            StateHasChanged();

            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, _pageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        _currentPage = 1;
        await LoadInitialDataAsync();
    }
}

